  "nexus": "0.0.0",
  "settings": {
    "model": "opus"
  },
  "plugins": [
    "animator",
    "astrolabe",
    "claude-code",
    "clerk",
    "clockworks-retry",
    "codexes",
    "fabricator",
    "laboratory",
    "loom",
    "oculus",
    "parlour",
    "ratchet",
    "spider",
    "stacks",
    "tools"
  ],
  "clerk": {
    "writTypes": [
      {
        "name": "brief",
        "description": "A minimal specification of a feature, needing further refinement in the Astrolabe"
      },
      {
        "name": "mandate",
        "description": "A request from the patron to complete a project"
      }
    ]
  },
  "astrolabe": {
    "generatedWritType": "mandate",
    "patronRole": "patron"
  },
  "loom": {
    "roles": {
      "steward": {
        "permissions": [
          "*:*"
        ]
      },
      "artificer": {
        "permissions": [
          "tools:*"
        ]
      },
      "reviewer": {
        "permissions": []
      }
    }
  },
  "animator": {
    "sessionProvider": "claude-code"
  },
  "laboratory": {
    "sanctumHome": "/workspace/nexus-mk2"
  },
  "codexes": {
    "settings": {
      "draftRoot": "/tmp/nexus-drafts"
    },
    "registered": {
      "nexus": {
        "remoteUrl": "git@github.com:shardworks/nexus.git"
      }
    }
  },
  "spider": {
    "role": "artificer",
    "buildCommand": "pnpm build",
    "testCommand": "pnpm test",
    "maxConcurrentEngines": 5,
    "variables": {
      "role": "artificer",
      "buildCommand": "pnpm build",
      "testCommand": "pnpm test"
    },
    "rigTemplateMappings": {
      "mandate": "default"
    },
    "rigTemplates": {
      "default": {
        "resolutionEngine": "seal",
        "engines": [
          {
            "id": "draft",
            "designId": "draft",
            "givens": {
              "writ": "${writ}"
            }
          },
          {
            "id": "implement",
            "designId": "implement",
            "upstream": [
              "draft"
            ],
            "givens": {
              "writ": "${writ}",
              "role": "${vars.role}"
            }
          },
          {
            "id": "review",
            "designId": "review",
            "upstream": [
              "implement"
            ],
            "givens": {
              "writ": "${writ}",
              "role": "reviewer",
              "buildCommand": "${vars.buildCommand}",
              "testCommand": "${vars.testCommand}"
            }
          },
          {
            "id": "revise",
            "designId": "revise",
            "upstream": [
              "review"
            ],
            "givens": {
              "writ": "${writ}",
              "role": "${vars.role}"
            }
          },
          {
            "id": "seal",
            "designId": "seal",
            "upstream": [
              "revise"
            ],
            "givens": {}
          }
        ]
      }
    }
  }
}

